import { v4 as uuidv4 } from 'uuid';

// --- Data Models ---

export interface Member {
    id: string;
    name: string;
    email: string;
}

export interface Team {
    id: string;
    name: string;
    ownerId: string; // ID of the the member who owns the team
    memberIds: string[]; // IDs of all members in the team
}

export interface Task {
    id: string;
    teamId: string;
    title: string;
    description: string;
    assignedToMemberId: string | null; // ID of the member assigned, or null if unassigned
}

// --- In-memory Database Simulation ---

const members: Member[] = [
    { id: 'member-1', name: 'Alice', email: 'alice@example.com' },
    { id: 'member-2', name: 'Bob', email: 'bob@example.com' },
    { id: 'member-3', name: 'Charlie', email: 'charlie@example.com' },
    { id: 'member-4', name: 'David', email: 'david@example.com' },
];

const teams: Team[] = [
    { id: 'team-1', name: 'Alpha Team', ownerId: 'member-1', memberIds: ['member-1', 'member-2'] },
    { id: 'team-2', name: 'Beta Team', ownerId: 'member-3', memberIds: ['member-3', 'member-4'] },
];

const tasks: Task[] = [
    { id: 'task-1', teamId: 'team-1', title: 'Design UI', description: 'Create mockups for new features', assignedToMemberId: 'member-2' },
    { id: 'task-2', teamId: 'team-1', title: 'Implement API', description: 'Develop backend endpoints', assignedToMemberId: 'member-1' },
    { id: 'task-3', teamId: 'team-1', title: 'Write Tests', description: 'Unit and integration tests', assignedToMemberId: 'member-2' },
    { id: 'task-4', teamId: 'team-2', title: 'Marketing Campaign', description: 'Plan social media strategy', assignedToMemberId: 'member-4' },
];

// --- Database Access Functions ---

export const findTeamById = (teamId: string): Team | undefined => {
    return teams.find(team => team.id === teamId);
};

export const findMemberById = (memberId: string): Member | undefined => {
    return members.find(member => member.id === memberId);
};

export const isTeamOwner = (teamId: string, memberId: string): boolean => {
    const team = findTeamById(teamId);
    return team?.ownerId === memberId;
};

export const isMemberOfTeam = (teamId: string, memberId: string): boolean => {
    const team = findTeamById(teamId);
    return team?.memberIds.includes(memberId) ?? false;
};

export const getTasksAssignedToMemberInTeam = (teamId: string, memberId: string): Task[] => {
    return tasks.filter(task => task.teamId === teamId && task.assignedToMemberId === memberId);
};

/**
 * Removes a member from a team and unassigns all their tasks within that team.
 * This function simulates a transaction.
 * @returns true if successful, false otherwise (e.g., member not found, owner removal attempt).
 */
export const removeMemberAndUnassignTasksTransaction = async (teamId: string, memberId: string): Promise<boolean> => {
    const teamIndex = teams.findIndex(t => t.id === teamId);
    if (teamIndex === -1) {
        console.error(`Team with ID ${teamId} not found.`);
        return false; // Team not found
    }

    const team = teams[teamIndex];

    if (!team.memberIds.includes(memberId)) {
        console.error(`Member with ID ${memberId} is not part of team ${teamId}.`);
        return false; // Member not in team
    }

    if (team.ownerId === memberId) {
        console.error(`Cannot remove team owner (ID: ${memberId}) from team ${teamId}.`);
        return false; // Cannot remove owner
    }

    // Simulate transaction:
    // 1. Prepare changes
    const newMemberIds = team.memberIds.filter(id => id !== memberId);
    const tasksToUnassign = tasks.filter(task => task.teamId === teamId && task.assignedToMemberId === memberId);

    // 2. Apply changes (in a real DB, this would be a single transaction block)
    try {
        // Update team members
        teams[teamIndex].memberIds = newMemberIds;

        // Unassign tasks
        tasksToUnassign.forEach(task => {
            const taskIndex = tasks.findIndex(t => t.id === task.id);
            if (taskIndex !== -1) {
                tasks[taskIndex].assignedToMemberId = null;
            }
        });

        console.log(`Member ${memberId} removed from team ${teamId} and ${tasksToUnassign.length} tasks unassigned.`);
        return true;
    } catch (error) {
        console.error('Transaction failed:', error);
        // In a real DB, you'd rollback here. For in-memory, we just report failure.
        return false;
    }
};
