import { Hono } from 'hono';
import { removeMemberAndUnassignTasksTransaction, findTeamById, findMemberById, isMemberOfTeam, isTeamOwner } from '../db';

const app = new Hono();

app.delete('/:teamId/members/:memberId', async (c) => {
    const { teamId, memberId } = c.req.param();

    if (!teamId || !memberId) {
        return c.json({ error: 'Team ID and Member ID are required.' }, 400);
    }

    const team = findTeamById(teamId);
    if (!team) {
        return c.json({ error: `Team with ID '${teamId}' not found.` }, 404);
    }

    const member = findMemberById(memberId);
    if (!member) {
        return c.json({ error: `Member with ID '${memberId}' not found.` }, 404);
    }

    if (!isMemberOfTeam(teamId, memberId)) {
        return c.json({ error: `Member '${memberId}' is not part of team '${teamId}'.` }, 400);
    }

    if (isTeamOwner(teamId, memberId)) {
        return c.json({ error: `Cannot remove team owner '${memberId}' from team '${teamId}'.` }, 403);
    }

    const success = await removeMemberAndUnassignTasksTransaction(teamId, memberId);

    if (success) {
        return c.json({ message: `Member '${memberId}' successfully removed from team '${teamId}' and tasks unassigned.` }, 200);
    } else {
        // This case should ideally be caught by the checks above,
        // but serves as a fallback for unexpected transaction failures.
        return c.json({ error: 'Failed to remove member and unassign tasks due to an internal error.' }, 500);
    }
});

export default app;
